#!/bin/bash

TARGET_DIR="/var/www-custom"

mkdir -p "$TARGET_DIR"

echo "Extracting payload..."

sed '1,/^PAYLOAD:$/d' "$0" | base64 -d | tar -xzf - -C "$TARGET_DIR"

echo "Done! Files are in $TARGET_DIR"

mountpoint -q /www && umount -l /www
mount /www /www

chmod +x "$TARGET_DIR/cgi-bin/ajax"

mount --bind "$TARGET_DIR/cgi-bin/ajax" /www/cgi-bin/ajax
mount --bind "$TARGET_DIR/menu/sub_menu_admin_inter" /www/menu/sub_menu_admin_inter
mount --bind "$TARGET_DIR/css/index.css" /www/css/index.css
mount --bind "$TARGET_DIR/css/main_style.css" /www/css/main_style.css
mount --bind "$TARGET_DIR/css/mainLeft.css" /www/css/mainLeft.css
mount --bind "$TARGET_DIR/image/logo_Intelbras_fiberhome.png" /www/image/logo_Intelbras_fiberhome.png
mount --bind "$TARGET_DIR/html/broadband_inter.html" /www/html/broadband_inter.html
mount --bind "$TARGET_DIR/html/login_inter.html" /www/html/login_inter.html
mount --bind "$TARGET_DIR/html/main_inter.html" /www/html/main_inter.html
mount --bind "$TARGET_DIR/html/snpwdauth_inter.html" /www/html/snpwdauth_inter.html
mount --bind "$TARGET_DIR/html/voice_base_inter.html" /www/html/voice_base_inter.html
mount --bind "$TARGET_DIR/html/ddns_new_inter.html" /www/html/ddns_new_inter.html
mount --bind "$TARGET_DIR/js/broadband_inter.js" /www/js/broadband_inter.js
mount --bind "$TARGET_DIR/js/ddns_new_inter.js" /www/js/ddns_new_inter.js
mount --bind "$TARGET_DIR/js/logView.js" /www/js/logView.js
mount --bind "$TARGET_DIR/js/page_access_check.js" /www/js/page_access_check.js
mount --bind "$TARGET_DIR/js/access.js" /www/js/access.js
mount --bind "$TARGET_DIR/js/snpwdauth_inter.js" /www/js/snpwdauth_inter.js
mount --bind "$TARGET_DIR/js/util.js" /www/js/util.js
mount --bind "$TARGET_DIR/js/voice_base_inter.js" /www/js/voice_base_inter.js
mount --bind "$TARGET_DIR/js/xhr.js" /www/js/xhr.js
mount --bind "$TARGET_DIR/js/wlanAdvancedSettings_inter.js" /www/js/wlanAdvancedSettings_inter.js
mount --bind "$TARGET_DIR/js/wlanAdvancedSettings_5G_inter.js" /www/js/wlanAdvancedSettings_5G_inter.js

kill $(ps aux | grep 'http' | grep -v 'grep' | awk '{print $1}')

sleep 3

exit 0

PAYLOAD:
